var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"휴우, 다행히 제가 확인한 고치는 별다른 이상이 없네요.","JPN":"ふぅ、幸い私が確認した繭に異常はありませんでした。","ENG":"Phew, there's nothing wrong with the cocoon that I saw.","TWN":"呼，我這裡確認繭沒有什麼異常。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"제 쪽도 마찬가지에요. 박사님의 걱정이 기우로 끝나서 다행이네요.","JPN":"こっちも同じです。博士の心配が杞憂で終わってくれてよかったです。","ENG":"Same here. I'm glad this was all just the doctor's worrying.","TWN":"我這邊也一樣。看來博士是白擔心一場，真是萬幸。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그나저나 네피림 사태 이전에 이곳은 상점가였던 것 같은데……","JPN":"ところで、ネフィリム事件の前は、ここは商店街だったようですが……","ENG":"Hey, wasn't this place a market street before the Nephil incident...?","TWN":"說起來，諾菲力事件發生之前，這裡好像是商店街。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"분위기 한 번 살벌하네요. 꼭 유령이라도 나올 것 같은데?","JPN":"すごい殺伐とした雰囲気ですね。まるで幽霊が出てきそうな？","ENG":"Sheesh, it's so creepy. I feel like a ghost might appear.","TWN":"如今看起來陰森森的，感覺會有幽靈飄出來。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"유, 유령!?","JPN":"ゆ、幽霊！？","ENG":"A-a ghost?!","TWN":"幽，幽靈？！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그, 그럴 리가 없잖아요!","JPN":"そ、そんなはずないでしょ！","ENG":"Th-there's no such thing as ghosts!","TWN":"怎，怎麼可能有幽靈！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아직 임무 중이라고요. 좀 더 진지해질 수 없나요?","JPN":"まだ任務は終わっていません。もうちょっと真剣になってくれませんか？","ENG":"Our mission isn't over. Could you please be more serious?","TWN":"我們還在執行任務中。你不能稍微認真一點嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mmm?","TWN":"嗯？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양, 방금 무슨 소리 안 들렸어요?","JPN":"カリンさん、今何か聞こえませんでしたか？","ENG":"Karin, did you hear that?","TWN":"卡琳，你剛剛有聽見什麼聲音嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨! 그러니까 임무 중에는 장난치지 말라고요!","JPN":"シノンさん！　だから任務中に悪戯はやめてくださいと言っているんです！","ENG":"Shiyoung! I told you not to kid around when on a mission!","TWN":"時雨！我說過，任務中別開玩笑！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 이번에는 장난이 아니라…… ","JPN":"ハハ、今のは悪戯じゃなくて…… ","ENG":"Hah hah, but it's not a joke this time–","TWN":"哈哈，這次真的不是開玩笑……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"방금!","JPN":"ほら！","ENG":"Just now!","TWN":"剛才！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"들었어요? 뭔가 지직거리는 소리가 났잖아요!","JPN":"聞こえました？　さっきの何かビリビリッとした音！","ENG":"Did you hear that? It sounded like something buzzing!","TWN":"聽見了嗎？窸窸窣窣的聲音！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저도 들었어요! 하늘 쪽에서 들렸던 것 같은데?","JPN":"私にも聞こえました！　空の方から聞こえたような？","ENG":"I heard it too! I think it came from up above.","TWN":"我也聽到了！好像是從空中傳來的？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"잠깐, 균열에서 뭔가가 튀어나오는 것 같은데요?","JPN":"待って、亀裂から何かが出てきていませんか？","ENG":"Wait, there's something coming out from the rift, I think?","TWN":"等一下，裂縫裡好像跑出來了什麼東西？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저건……?","JPN":"あれは……？","ENG":"Isn't that...?","TWN":"那個是……？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이쪽으로 떨어지고 있어요! 피해요!","JPN":"こっちに落ちてきます！　避けてください！","ENG":"It's crashing toward us! Look out!","TWN":"往這邊掉下來了！快閃開！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"콜록, 콜록……!","JPN":"ゲホッ、ゲホッ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳……！"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저건…… <color=#ffd34c>차원 함선</color>이잖아?","JPN":"あれは……<color=#ffd34c>次元艦船</color>？","ENG":"Is that... a <color=#ffd34c>dimensional ship</color>?","TWN":"這是……<color=#ffd34c>次元艦船</color>？"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"우리 함선보다 훨씬 크네요. 저렇게 커다란 함선은 처음 봐요!","JPN":"私たちの艦船よりずっと大きいですね。あんなに大きい艦船は初めて見ます！","ENG":"It's even bigger than ours. I've never seen such a massive ship before!","TWN":"這比我們的艦船大多了。第一次看到這種大艦船！"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"잠깐만요, 어쩌면 저 함선……","JPN":"ちょっと待って、もしかするとあの艦船って……","ENG":"Hold on, maybe that ship...","TWN":"等等，這艘艦船……"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"<color=#ffd34c>로스트 쉽</color>일지도 몰라요!","JPN":"<color=#ffd34c>ロストシップ</color>かもしれません！","ENG":"Could be a <color=#ffd34c>Lost Ship</color>!","TWN":"說不定是<color=#ffd34c>失落艦船</color>！"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"로스트 쉽?","JPN":"ロストシップ？","ENG":"A Lost Ship?","TWN":"失落艦船？"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아아, 저도 들어 본 적 있는 것 같네요.","JPN":"ああ、私も聞いたことがあるような気がします。","ENG":"Oh, I think I've heard of something like that before.","TWN":"啊啊，這個名字我好像也聽過。"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아마 가끔씩 세계 어딘가 혹은 이면세계에서 발견된다는 정체불명의 함선.","JPN":"たぶん、たまに世界のどこか、あるいは裏世界のどこかで発見されるという正体不明の艦船。","ENG":"The mysterious ship that is randomly found in Counterside or even here.","TWN":"據傳，偶爾會在世界的某個角落或者異界中出現的神秘艦船。"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"누가, 어디서, 어떤 목적으로, 어떻게 거기 버려졌는지 아무도 모른다는 그거 맞죠?","JPN":"誰が、どこで、どんな目的で、どうやってそこに捨てたのか誰も知らないという、あれですよね？","ENG":"Nobody knows who, where, why, or how it got there, right?","TWN":"至於是誰？在哪？什麼目的？為什麼被遺棄在那裡？這些都是未知數，對吧？"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리 세계에는 저런 거대 함선을 건조할 수 있는 자원도, 그걸 숨길 수 있는 기술도 없어요.","JPN":"私たちの世界にはあんな巨大な艦船を建造できる資源も、それを隠す技術もありません。","ENG":"Our world doesn't have the resources to build a ship this big or the technology to hide it.","TWN":"我們世界既沒有建造這種艦船的資源，也沒有隱藏他的技術。"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"틀림없어요. 저건 분명 다른 세계에서 떨어진 함선이에요!","JPN":"間違いありません。あれはきっと別の世界から落ちてきた艦船です！","ENG":"There's no other explanation. It has to be a ship from another world!","TWN":"沒錯。這肯定是從其他世界中墜落的艦船！"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"다른 세계로부터 온 차원 함선이라…….","JPN":"別の世界から来た次元艦船か……","ENG":"A dimensional ship from another world, you say...","TWN":"從其他世界來的次元艦船啊……"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"소문에 따르면 로스트 쉽 안에는 재미있는 물건들이 많이 발견된다고 하던데요?","JPN":"噂によるとロストシップの内部からは面白い物がたくさん見つかるそうですよ？","ENG":"Aren't there rumors about interesting things being found on Lost Ships?","TWN":"據說，可以在失落艦船裡找到好多有意思的東西？"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"예를 들면, 고순도 이터니움 주괴가 박스째로 들어 있다거나, 진귀한 아티팩트가 발견된다거나…….","JPN":"例えば、高純度エタニウムの塊が箱ごと見つかるとか、貴重なアーティファクトが見つかるとか……","ENG":"Such as boxes full of high-purity Eternium ingots, or rare Artifacts...","TWN":"比如，大塊大塊的高純度永恆之金成箱裝在上面，還有珍貴的人造神器……"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"뭐, 다 소문뿐이긴 하지만요.","JPN":"まあ、すべて噂に過ぎないんですけどね。","ENG":"It's all hearsay, though.","TWN":"不過，這些也只不過是傳聞而已。"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그게 소문인지 아닌지는 이제 알게 되겠죠.","JPN":"噂かどうかは、確かめればわかります。","ENG":"We'll find out if they are just rumors or not.","TWN":"究竟是不是傳聞，馬上就能知道了。"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"자, 어서 확인하러 가봐요!","JPN":"さぁ、早く見に行きましょう！","ENG":"Come on, let's go!","TWN":"好，我們去確認一下吧！"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"후후, 카린 양은 첨단 기계만 보면 선물 받은 아이 표정을 짓는다니까요?","JPN":"ふふ、カリンさんたら先端機器となると、プレゼントを貰った子どもみたいに相好を崩すんですから。","ENG":"Heh heh, you look like a kid on Christmas every time you see high-tech machinery, Karin.","TWN":"呵呵，卡琳一看到高科技的機器，就會露出小孩子收到禮物一樣的表情呢？"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"누, 누구보고 어린 애라는 거예요! 난 당신 고용주라고!","JPN":"だ、誰が子どもですか！　私はあなたの雇い主なのよ？","ENG":"W-who are you calling a kid?! I'm your employer!","TWN":"說，說誰是小孩！我可是你的雇主！"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어라? 빨리 안 오고 뭐해요, 카린 양!","JPN":"あれ？　行かないんですか、カリンさん！","ENG":"Oh? Hurry, Karin! Why aren't you coming?","TWN":"啊呀？別愣著，卡琳你快點過來！"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"언제 저기까지! 같이 가요, 시영 씨!","JPN":"いつの間にあんなに進んで……！　待ってください、シノンさん！","ENG":"How did you get there so fast? Wait for me, Shiyoung!","TWN":"你什麼時候跑前面去了！等我！"},"stage":{"bg":"EXILER_07","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이거, 이거…….","JPN":"これはこれは……","ENG":"My, my...","TWN":"這個，這是……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어쩌면 저희가 엄청난 걸 발견해버린 걸지도 모르겠는데요, 카린 양?","JPN":"もしかしたらとんでもないものを見つけてしまったのかもしれませんね、私たち。","ENG":"We may have found something incredible. What do you think, Karin?","TWN":"我們可能發現了個了不得的東西呢，卡琳？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……말도 안 돼.","JPN":"……嘘でしょ。","ENG":"...This is astounding.","TWN":"……怎麼可能。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대체 이 어마어마한 양의 무기들은 뭐죠?","JPN":"このとんでもない量の武器は、いったい何なの？","ENG":"What are all these weapons even for?","TWN":"這些數量如此驚人的武器到底是？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"개인 화기뿐만이 아니야. 중화기, 도검류 그리고 야구 배트?","JPN":"個人用の火器だけじゃないわ。重火器に、刀剣類、それに野球バット？","ENG":"There aren't just firearms, but heavy artillery, swords, and a baseball bat?","TWN":"不只有槍，還有各種重型武器、刀劍，跟球棒？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이런 건 어떻게 쓰는 거지?","JPN":"これはいったいどうやって使うのかしら？","ENG":"I wonder what that's for.","TWN":"這個要怎麼用啊？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"구조를 파악하는 것 정도라면 내 분석 능력으로……","JPN":"構造を把握するくらいなら、私の分析能力で……","ENG":"I can use my analysis skills to figure out the structure–","TWN":"如果只是要掌握構造，以我的分析能力……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"큿!? 능력이 듣질 않아?","JPN":"くっ！？　能力が効かない？","ENG":"Kgh?! My ability doesn't work?","TWN":"咳！能力沒有用嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"장비에 강력한 프로텍트가 걸려 있어서, 제 능력으로도 구조를 해석할 수가 없어요.","JPN":"装備に強力なプロテクトがかかっていて、私の能力でも構造を解析することができません。","ENG":"The gear has some kind of powerful protection on it. I can't analyze any of them.","TWN":"裝備上有強大的防護器，就算以我的能力也無法分析他的構造。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 분명한 건, 이 장비들 하나하나가 특정 카운터를 대상으로 맞춤 설계한 장비라는 거예요!","JPN":"でも確かなのは、ここの装備一つ一つが特定のカウンター用にカスタマイズされているということです！","ENG":"But what I do know is that every weapon has been custom designed for specific Counters!","TWN":"但可以肯定，這些裝備每一個都是針對特定制裁者量身製作的！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이런 무기들로 함선을 가득 채우고 있다니…….","JPN":"こういった武器を艦船いっぱいに積んでいるなんて……","ENG":"A ship full of weapons like these...?","TWN":"這種武器，艦船裡竟然滿滿都是……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"마치 함선 전체가 무기를 저장하고 있는 <color=#ffd34c>무기고</color> 같잖아?","JPN":"まるで艦船全体が武器を保管する<color=#ffd34c>武器庫</color>みたいだわ。","ENG":"It's as if the entire ship is an <color=#ffd34c>arsenal</color>!","TWN":"這艘艦船就好像是一個貯存武器的<color=#ffd34c>武器庫</color>？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨, 어서 방위군에 이 사실을 알려야 해요!","JPN":"シノンさん、早くこのことを防衛軍に知らせなくちゃ！","ENG":"Shiyoung, we must report this to the Defense Force immediately!","TWN":"時雨，快向保衛軍報告這件事！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 함선과 무기를 우리 것으로 만들 수만 있다면 우리 세계의 멸망을 막는 것도 꿈이 아니라고요!","JPN":"この艦船と武器を回収できたら、私たちの世界の滅亡を食い止めるのも夢じゃありませんよ！","ENG":"If we can make this ship and its weapons ours, saving our world from destruction will be more than just a pipe dream!","TWN":"這艘艦船和武器要是能為我們所用，阻止世界的滅亡就不再是夢了！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양, 방금 들었어요?","JPN":"カリンさん、今聞こえました？","ENG":"Karin, did you hear that just now?","TWN":"卡琳，你聽到剛才的動靜了嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……네. 함교 쪽에서 무슨 소리가 났어요.","JPN":"……はい、艦橋から何か音がしましたね。","ENG":"...Yes. I heard noises coming from the bridge.","TWN":"……嗯，艦橋那邊有什麼聲音。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그러고보니 이상하지 않아요, 카린 양?","JPN":"そういえばおかしいと思いませんか、カリンさん？","ENG":"Now that I think of it, isn't it odd, Karin?","TWN":"這樣說來，你不覺得奇怪嗎，卡琳？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이 로스트 쉽, 우리가 보는 눈 앞에서 갑자기 나타났잖아요.","JPN":"このロストシップ、私たちの目の前にいきなり現れたじゃないですか。","ENG":"This Lost Ship, it suddenly appeared right in front of our eyes.","TWN":"這艘失落艦船，就這麼突然出現在我們面前。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어쩌면 함선을 조종하던 사람이 함내에 남아 있을 가능성도 있지 않을까요?","JPN":"艦船を操縦していた誰かが船内に残っていてもおかしくないですよね？","ENG":"Perhaps that means that the person who controlled it is still onboard?","TWN":"或許，操控艦船的人還在裡面？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"확실히 일리가 있네요.","JPN":"確かに、そのとおりですね。","ENG":"You have a point there.","TWN":"確實有這個可能。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 이 정도 거대 함선을 운용하기 위해서는 다수의 오퍼레이터가 필요할 거예요.","JPN":"でも、これほどの巨大な艦船を運用するには、多くのオペレーターが必要なはずです。","ENG":"But operating a ship this massive will require many operators.","TWN":"要駕駛這種巨型艦船，需要多個領航員。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"함 내부에는 그런 인기척이 느껴지지는 않는 걸요.","JPN":"船内には、そのような人の気配はありません。","ENG":"And I don't sense that kind of energy from within the ship.","TWN":"可艦船內卻感覺不到人的氣息。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"만약 함 내에 누군가가 있다면…….","JPN":"もし船内に誰かがいるとしたら……","ENG":"If there is still someone onboard the ship...","TWN":"如果艦船內有人的話……"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저희 입장에서는 그 누군가가 <color=#ffd34c>엑자일러</color>가 되겠네요.","JPN":"私たちからすると、その誰かが<color=#ffd34c>エグザイラー</color>ということになりますね。","ENG":"That someone would be an <color=#ffd34c>Exile</color> to us.","TWN":"對於我們來說，他就是<color=#ffd34c>流浪者</color>。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그렇다면 그 엑자일러는 과연 우연히 차원 균열에 휘말린 걸까요?","JPN":"なら、そのエグザイラーは偶然次元の亀裂に巻き込まれたんでしょうか？","ENG":"Then, that Exile just happened to get caught in a dimensional rift?","TWN":"那麼，這個流浪者究竟是不是偶然被捲入次元裂縫的呢？"},"stage":{"bg":"SS_CROSSLOAD_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어쩌면 크로스로드 때의 저희처럼 <color=#ffd34c>어떤 의도</color>를 가지고 이 세계에 온 걸지도 모르죠.","JPN":"もしかするとクロスロード作戦のときの私たちみたいに<color=#ffd34c>何らかの意図</color>を持って、この世界に来たのかもしれません。","ENG":"Maybe this person came to this world with a <color=#ffd34c>certain purpose</color>, just like us during Crossroads.","TWN":"說不定，和十字路口作戰時的我們一樣，帶著<color=#ffd34c>某種目的</color>來到這個世界的。"},"stage":{"bg":"SS_CROSSLOAD_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어떤 의도라고요?","JPN":"何らかの意図？","ENG":"A certain purpose?","TWN":"某種目的？"},"stage":{"bg":"SS_CROSSLOAD_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"생각해보세요, 카린 양.","JPN":"よく考えてみてください、カリンさん。","ENG":"Think about it, Karin.","TWN":"卡琳，你想一想。"},"stage":{"bg":"SS_CROSSLOAD_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이렇게 수많은 무기들을 실은 함선으로 다른 세계를 방문한다는 게, 과연 어떤 의도일까요?","JPN":"これだけの大量の武器を積んだ艦船で、別の世界に訪問することが何を意味するか。","ENG":"What do you think it means when an arsenal ship comes to another world?","TWN":"究竟是帶著什麼樣的目的，才會駕駛這艘裝載了如此多武器的艦船，探訪其他世界呢？"},"stage":{"bg":"SS_CROSSLOAD_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"설마, <color=#ffd34c>전쟁</color>이라는 뜻인가요?","JPN":"まさか、<color=#ffd34c>戦争</color>でしょうか？","ENG":"Do you mean... they want to start a <color=#ffd34c>war</color>?","TWN":"你的意思是，他們想要發動一場<color=#ffd34c>戰爭</color>嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"글쎄요? 뭐, 속단하기는 이르겠지만요.","JPN":"どうでしょうね？　まぁ、断定はまだできませんが。","ENG":"I dunno. It's too early to tell.","TWN":"這個嘛？唔，現在下結論還之過早。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이렇게 좁은 공간에서는 나이프를 쓰는 제가 앞장서는 편이 좋겠네요.","JPN":"ここは狭いですから、ナイフ使いの私が先頭に立った方がいいでしょう。","ENG":"In tight spaces like this, I think it's better if I take the lead since I'm better with knives than you.","TWN":"在這種窄小的空間裡，還是擅長近身戰的我走前面吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"최대한 발소리를 죽이고 천천히 따라오세요, 카린 양.","JPN":"できるだけ音を立てずについてきてくださいね、カリンさん。","ENG":"Karin, just slowly follow me and try not to make any noises.","TWN":"卡琳，盡量放輕腳步聲，慢慢跟著我。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아무도 없나?","JPN":"誰もいないのかな？","ENG":"Is there nobody here?","TWN":"沒人嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요. 저쪽에 누군가가 쓰러져 있어요.","JPN":"いいえ。あそこに誰かが倒れています。","ENG":"Look, someone's fainted over there.","TWN":"不，那邊躺著一個人。"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"너무 가까이 가지 않는 편이 좋을 것 같아요. 양쪽에서 포위하면서 접근하죠.","JPN":"あまり近づかない方がいいかもしれません。両側から包囲しながら接近しましょう。","ENG":"Don't get too close. Let's approach her from both sides just to be safe.","TWN":"別靠太近比較好。我們二頭包抄靠近他。"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"잠깐, 설마 저 사람이 입고 있는 복장은……?","JPN":"待って、あの人の服装って……？","ENG":"Wait, the uniform she's wearing...","TWN":"等一下，那個人穿的衣服，該不會是……？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"으윽. 여기는 대체……?","JPN":"ううっ。ここは……？","ENG":"Ngh, where am I...?","TWN":"呃，這是……哪裡……？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"머리 위로 손을 올리고 이쪽 지시에 따르세요!","JPN":"手を上げて、こちらの指示に従いなさい！","ENG":"Put your hands in the air and do as we say!","TWN":"把手舉起來，聽從我們的指示！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저항하면 즉시 발포하겠습니다!","JPN":"抵抗すれば即発砲します！","ENG":"Show any signs of resisting, and we will shoot!","TWN":"反抗的話，我們會立即開火！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"누구죠? 당신들은?","JPN":"誰ですか？　あなたたちは？","ENG":"Who are you people?","TWN":"誰？你們是？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"질문은 이쪽에서 합니다!","JPN":"質問はこちらが行います！","ENG":"We ask the questions here!","TWN":"這是我們該問的問題！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신이야말로 누구입니까?","JPN":"あなたこそ誰なんですか？","ENG":"Who are you?","TWN":"你是誰？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대체 누구인데 델타 세븐의 대원복을 입고 있는 거죠?","JPN":"あなたはいったい何者で、なぜデルタセブンの制服を着ているのですか？","ENG":"And why are you wearing a Delta Seven uniform?","TWN":"你到底是誰？為什麼會穿著第七三角洲部隊的隊服？？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"대원복? 무슨 말을 하는 건가요?","JPN":"制服？　何のことですか？","ENG":"Uniform? What are you talking about?","TWN":"隊服？你說什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"으음, 이거 곤란하게 됐네요.","JPN":"うーん、これは困りましたね。","ENG":"Mm, this is tricky.","TWN":"唔，麻煩了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아무래도 이 사람, 기억을 잃은 것 같은데요?","JPN":"どうやらこの人、記憶喪失みたいですよ？","ENG":"I think this person is suffering from memory loss.","TWN":"看來這個人喪失了記憶？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"기억을 잃었다고?","JPN":"記憶喪失？","ENG":"Memory loss?","TWN":"喪失記憶？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"그보다 여기가 어디죠? 그리고 델타 세븐이라는 건?","JPN":"それよりここはどこなんですか？　それにデルタセブンとは？","ENG":"Where am I? And what is Delta Seven?","TWN":"對了，這是哪裡？然後第七三角洲部隊是什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"그리고 저는…….","JPN":"それに私は……","ENG":"Who am I....?","TWN":"還有我是……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저도 당신이 어디서 왔는지, 누구인지 모릅니다.","JPN":"私もあなたがどこから来たのか、何者なのかわかりません。","ENG":"I don't know who or where you're from.","TWN":"我不知道你來自哪裡，也不知道你是誰。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 당신이 그 대원복을 입고 있다는 건, 당신에게도 뭔가 잊어서는 안 되는 사명이라는 게 있다는 뜻이겠죠.","JPN":"しかしあなたがその制服を着ているということは、あなたには何か忘れてはいけない使命があるということです。","ENG":"But that uniform shows that you have a duty that you must not forget.","TWN":"但既然你穿著那件隊服，那就說明你身上有著決不能忘記的使命。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"자, 다시 묻겠습니다.","JPN":"それでは、もう一度聞きます。","ENG":"I'll ask you again.","TWN":"好了，我重新問一遍。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신은 누구죠? 다른 대원들은 어떻게 된 겁니까?","JPN":"あなたは誰ですか？　他の隊員たちはどうしたのですか？","ENG":"Who are you? What happened to the other members?","TWN":"你是誰？其他的隊員們在哪裡？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"안토노프.","JPN":"アントノフ。","ENG":"Antonov.","TWN":"安東諾夫。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아마도 저는 다른 분들께 <color=#ffd34c>안토노프</color>라는 이름으로 불렸었던 것 같습니다.","JPN":"おそらく私は、他の者からは<color=#ffd34c>アントノフ</color>と呼ばれていたようです。","ENG":"I think that's what they called me. <color=#ffd34c>Antonov</color>.","TWN":"他們好像都叫我<color=#ffd34c>安東諾夫</color>。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"안토노프?","JPN":"アントノフ？","ENG":"Antonov?","TWN":"安東諾夫？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양, 델타 세븐에 그런 사람이 있나요?","JPN":"カリンさん、デルタセブンにそんな人いましたか？","ENG":"Karin, was there anyone like her in Delta Seven?","TWN":"卡琳，第七三角洲部隊有這個人嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요. 제가 아는 한 처음 들어보는 이름입니다.","JPN":"いいえ。私の知る限りでは初めて聞く名前です。","ENG":"No, it's the first time hearing that name.","TWN":"沒有。我第一次聽說這個名字。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 외에는……","JPN":"他には……","ENG":"Other than that...","TWN":"除此之外……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"유감스럽지만 그 외에는 잘 떠오르지 않는군요.","JPN":"残念ながら、それ以外はうまく思い出せません。","ENG":"I'm sorry, but nothing else comes to mind.","TWN":"很遺憾，其他的我想不起來了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SHADOW_EXILER_NPC_QM","text":{"KOREA":"<color=#ff3636>…….</color>","JPN":"<color=#ff3636>……</color>","ENG":"<color=#ff3636>...</color>","TWN":"<color=#ff3636>……</color>"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_EXILER_NPC_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L19_1","type":"dialog","speaker":"SHADOW_EXILER_NPC_QM","text":{"KOREA":"<color=#ff3636>죽여.</color>","JPN":"<color=#ff3636>殺せ。</color>","ENG":"<color=#ff3636>Kill.</color>","TWN":"<color=#ff3636>殺</color>"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_EXILER_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SHADOW_EXILER_NPC_QM","text":{"KOREA":"<color=#ff3636>우리의 적을 죽여.</color>","JPN":"<color=#ff3636>我らの敵を殺せ。</color>","ENG":"<color=#ff3636>Kill our enemies.</color>","TWN":"<color=#ff3636>殺死我們的敵人。</color>"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_EXILER_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SHADOW_EXILER_NPC_QM","text":{"KOREA":"<color=#ff3636>죽이고, 또 죽여서</color>","JPN":"<color=#ff3636>殺して、殺しまくって</color>","ENG":"<color=#ff3636>Kill and kill again.</color>","TWN":"<color=#ff3636>殺戮，不停地殺戮。</color>"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_EXILER_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SHADOW_EXILER_NPC_QM","text":{"KOREA":"<color=#ff3636>모조리…… 죽여 없애는 거야…….</color>","JPN":"<color=#ff3636>一人残らず……消すのだ……</color>","ENG":"<color=#ff3636>Exterminate... them all...</color>","TWN":"<color=#ff3636>一個不留……全部……</color>"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_EXILER_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SHADOW_EXILER_NPC_QM","text":{"KOREA":"<color=#ff3636>으윽, 그렇지 않으면…… 그렇지 않으면……!!</color>","JPN":"<color=#ff3636>ううっ、そうしなければ……そうしなければ……！！</color>","ENG":"<color=#ff3636>Ngh, or else... Or else...!!</color>","TWN":"<color=#ff3636>啊啊，不然的話……不然的話……！！</color>"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_EXILER_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SHADOW_EXILER_NPC_QM","text":{"KOREA":"<color=#ff3636>끄윽……! 크아아아아아아아악……!!</color>","JPN":"<color=#ff3636>くうっ……！　ぐわああああっ……！！</color>","ENG":"<color=#ff3636>Kgh...! Kraaaawr...!!</color>","TWN":"<color=#ff3636>呃……！呃啊啊啊啊啊……！！</color>"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_EXILER_NPC_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_02"}]`);export{e as default};